    82→
    83→export function sendMessageStream(
    84→  conversationId: string,
    85→  message: string,
    86→  onChunk: (chunk: StreamChunk) => void,
    87→  onDone: () => void,
    88→  onError: (err: unknown) => void
    89→): void {
    90→  fetch(`/api/conversations/${conversationId}/messages/stream`, {
    91→    method: 'POST',
    92→    headers: JSON_HEADERS,
    93→    body: JSON.stringify({ message }),
    94→  })
    95→    .then(async (res) => {
    96→      if (!res.ok || !res.body) {
    97→        onError(new Error(res.statusText));
    98→        return;
    99→      }
   100→      const reader = res.body.getReader();
   101→      const decoder = new TextDecoder();
   102→      let buffer = '';
   103→      while (true) {
   104→        const { done, value } = await reader.read();
   105→        if (done) break;
   106→        buffer += decoder.decode(value, { stream: true });
   107→        const events = buffer.split('\n\n');
   108→        buffer = events.pop() ?? '';
   109→        for (const event of events) {
   110→          const dataLine = event.split('\n').find((l) => l.startsWith('data:'));
   111→          if (dataLine) {
   112→            const data = dataLine.slice(5).trim();
   113→            if (data) {
   114→              try {
   115→                onChunk(JSON.parse(data) as StreamChunk);
   116→              } catch {
   117→                // skip non-JSON
   118→              }
   119→            }
   120→          }
   121→        }
   122→      }
   123→      if (buffer.trim()) {
   124→        const dataLine = buffer.split('\n').find((l) => l.startsWith('data:'));
   125→        if (dataLine) {
   126→          const data = dataLine.slice(5).trim();
   127→          if (data) {
   128→            try {
   129→              onChunk(JSON.parse(data) as StreamChunk);
   130→            } catch {
   131→              // skip
   132→            }
   133→          }
   134→        }
   135→      }
   136→      onDone();
   137→    })
   138→    .catch(onError);
   139→}
