    19→type TreeNode = Conversation & { children: TreeNode[] };
    20→
    21→function formatCreationTime(ms: number): string {
    22→  const d = new Date(ms);
    23→  const now = new Date();
    24→  const sameDay = d.getDate() === now.getDate() && d.getMonth() === now.getMonth() && d.getFullYear() === now.getFullYear();
    25→  if (sameDay) {
    26→    return d.toLocaleTimeString(undefined, { hour: '2-digit', minute: '2-digit' });
    27→  }
    28→  const yesterday = new Date(now);
    29→  yesterday.setDate(yesterday.getDate() - 1);
    30→  if (d.getDate() === yesterday.getDate() && d.getMonth() === yesterday.getMonth()) {
    31→    return 'Yesterday ' + d.toLocaleTimeString(undefined, { hour: '2-digit', minute: '2-digit' });
    32→  }
    33→  return d.toLocaleDateString(undefined, { day: 'numeric', month: 'short' }) + ' ' + d.toLocaleTimeString(undefined, { hour: '2-digit', minute: '2-digit' });
    34→}
    35→
    36→function byNewestFirst(a: { createdAtMillis?: number | null }, b: { createdAtMillis?: number | null }): number {
    37→  const ta = a.createdAtMillis ?? 0;
    38→  const tb = b.createdAtMillis ?? 0;
    39→  return tb - ta;
    40→}
    41→
    42→function buildTree(conversations: Conversation[]): TreeNode[] {
    43→  const sorted = [...conversations].sort(byNewestFirst);
    44→  const byId = new Map<string, TreeNode>();
    45→  for (const c of sorted) {
    46→    byId.set(c.id, { ...c, children: [] });
    47→  }
    48→  const roots: TreeNode[] = [];
    49→  for (const c of sorted) {
    50→    const node = byId.get(c.id)!;
    51→    const pid = c.parentConversationId ?? null;
    52→    if (pid == null) {
    53→      roots.push(node);
    54→    } else {
    55→      const parent = byId.get(pid);
    56→      if (parent) parent.children.push(node);
    57→      else roots.push(node);
    58→    }
    59→  }
    60→  for (const node of byId.values()) {
    61→    node.children.sort(byNewestFirst);
    62→  }
    63→  return roots;
    64→}
    65→
    66→function hasActiveDescendant(node: TreeNode, activeId: string | null): boolean {
    67→  if (!activeId) return false;
    68→  if (node.id === activeId) return true;
    69→  return node.children.some((c) => hasActiveDescendant(c, activeId));
    70→}
